# Create segmentation based on multiple dimensions
# We'll use: spending level, activity status, tenure, and plan tier

# Define spending tiers
def categorize_spending(spend):
    if spend == 0:
        return 'Zero Spend'
    elif spend < 10:
        return 'Low Spend'
    elif spend < 50:
        return 'Medium Spend'
    else:
        return 'High Spend'

# Define tenure tiers
def categorize_tenure(months):
    if months < 3:
        return 'New'
    elif months < 12:
        return 'Growing'
    elif months < 24:
        return 'Established'
    else:
        return 'Veteran'

df_clean['spend_tier'] = df_clean['monthly_spend_clean'].apply(categorize_spending)
df_clean['tenure_tier'] = df_clean['tenure_months'].apply(categorize_tenure)

# Create comprehensive segments
def create_segment(row):
    spend = row['monthly_spend_clean']
    active = row['is_active']
    tenure = row['tenure_months']
    plan = row['plan_tier']

    # High-value segments
    if spend >= 50 and active:
        return 'Champions'
    elif spend >= 50 and not active:
        return 'At-Risk High Value'

    # Medium spenders
    elif spend >= 10 and spend < 50 and active and tenure >= 12:
        return 'Loyal Customers'
    elif spend >= 10 and spend < 50 and active and tenure < 12:
        return 'Promising'
    elif spend >= 10 and spend < 50 and not active:
        return 'At-Risk Medium Value'

    # Low/Zero spenders
    elif spend > 0 and spend < 10 and active and tenure >= 6:
        return 'Engaged Low Spenders'
    elif spend > 0 and spend < 10 and active and tenure < 6:
        return 'New Explorers'
    elif spend > 0 and not active:
        return 'Dormant Low Value'

    # Zero spenders
    elif spend == 0 and active and tenure < 3:
        return 'New Free Users'
    elif spend == 0 and active and tenure >= 3:
        return 'Long-term Free Users'
    else:
        return 'Churned Free Users'

df_clean['segment'] = df_clean.apply(create_segment, axis=1)

print("Segment distribution:")
segment_summary = df_clean['segment'].value_counts()
print(segment_summary)
print(f"\nTotal users: {len(df_clean)}")
